{
    "title": "6. Ćwiczenia",
    "select_title": "Ćwiczenie 1. Wybierz poprawną opcję",
    "select_intro": "Wybierz zdanie, w którym wyrażenie czasu pasuje do Past Simple.",
    "selects": [
        {
            "label": "a) I visited them yesterday. / b) I visit them yesterday.",
            "prompt": "Która opcja jest poprawna?",
            "answer": "a"
        },
        {
            "label": "a) She sees him two days ago. / b) She saw him two days ago.",
            "prompt": "Która opcja jest poprawna?",
            "answer": "b"
        },
        {
            "label": "a) We moved here in 2021. / b) We move here in 2021.",
            "prompt": "Która opcja jest poprawna?",
            "answer": "a"
        }
    ],
    "options": [
        "a",
        "b"
    ],
    "input_title": "Ćwiczenie 2. Zbuduj zdanie z markerem czasu",
    "input_intro": "Ułóż słowa w poprawnej kolejności i użyj Past Simple.",
    "inputs": [
        {
            "before": "I / call her / yesterday",
            "after": "→",
            "answer": "I called her yesterday."
        },
        {
            "before": "They / arrive / two days ago",
            "after": "→",
            "answer": "They arrived two days ago."
        },
        {
            "before": "She / move to Warsaw / in 2020",
            "after": "→",
            "answer": "She moved to Warsaw in 2020."
        }
    ],
    "rephrase_title": "Ćwiczenie 3. Popraw błędy",
    "rephrase_intro": "Znajdź błąd w zdaniu z markerem czasu przeszłego.",
    "rephrase": [
        {
            "example_label": "Przykład:",
            "example_original": "I go there yesterday.",
            "example_target": "I went there yesterday."
        },
        {
            "original": "1. I go there yesterday.",
            "placeholder": "Popraw zdanie",
            "answer": "I went there yesterday."
        },
        {
            "original": "2. She didn't saw him last night.",
            "placeholder": "Popraw zdanie",
            "answer": "She didn't see him last night.",
            "accepted": [
                "She didn't see him last night.",
                "She did not see him last night."
            ]
        },
        {
            "original": "3. We visit them two days ago.",
            "placeholder": "Popraw zdanie",
            "answer": "We visited them two days ago."
        }
    ]
}
